+        ];
+        let order = topological_sort_steps(&steps);
+        let pos = |id: &str| order.iter().position(|s| s == id).unwrap();
+        assert!(pos("a") < pos("b"));
+        assert!(pos("a") < pos("c"));
+        assert!(pos("b") < pos("d"));
